    const thinkingInterval = setInterval(updateThinkingMessage, 500);

    // Generate a random delay between 3 and 4 seconds
    const delay = Math.floor(Math.random() * 1000) + 3000;
    setTimeout(() => {
        // Clear the 'Thinking' message interval
        clearInterval(thinkingInterval);

        // Fade out the 'Thinking' message with CSS transition set before making it invisible.
        message.style.transition = 'opacity 1s ease';
        message.style.opacity = '0'; 

